import{_ as d,o as a,c as r,ag as l}from"./chunks/framework.Vng7Hdlh.js";const c=JSON.parse('{"title":"10. プラン・コース管理","description":"","frontmatter":{},"headers":[],"relativePath":"internal/features/10-plans.md","filePath":"internal/features/10-plans.md"}'),e={name:"internal/features/10-plans.md"};function h(i,t,o,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[l(`<h1 id="_10-プラン・コース管理" tabindex="-1">10. プラン・コース管理 <a class="header-anchor" href="#_10-プラン・コース管理" aria-label="Permalink to &quot;10. プラン・コース管理&quot;">​</a></h1><p>管理ダッシュボードの「プラン・コース」タブでは、食べ放題プラン（時間制限付きプラン）とコース料理テンプレートを管理します。マネージャー以上のロールで利用できます。</p><h2 id="_10-1-食べ放題プラン" tabindex="-1">10.1 食べ放題プラン <a class="header-anchor" href="#_10-1-食べ放題プラン" aria-label="Permalink to &quot;10.1 食べ放題プラン&quot;">​</a></h2><h3 id="プラン一覧" tabindex="-1">プラン一覧 <a class="header-anchor" href="#プラン一覧" aria-label="Permalink to &quot;プラン一覧&quot;">​</a></h3><p>「プラン・コース」タブ → 「食べ放題プラン」サブタブを選択すると、登録済みプランの一覧が表示されます。</p><p>各プランには以下の情報が表示されます。</p><table tabindex="0"><thead><tr><th>表示要素</th><th>説明</th></tr></thead><tbody><tr><td>プラン名</td><td>日本語名（英語名があればカッコ内に表示）</td></tr><tr><td>制限時間</td><td>「90分」形式</td></tr><tr><td>ラストオーダー</td><td>「LO 15分前」形式</td></tr><tr><td>価格</td><td>「¥2,980」形式</td></tr><tr><td>ステータスバッジ</td><td>緑色「有効」/ 赤色「無効」</td></tr><tr><td>並び順</td><td>表示順の数値</td></tr><tr><td>「メニュー管理」ボタン</td><td>プラン専用メニューの展開</td></tr><tr><td>「編集」ボタン</td><td>プランの編集</td></tr><tr><td>「削除」ボタン</td><td>プランの削除</td></tr></tbody></table><h3 id="プランの追加" tabindex="-1">プランの追加 <a class="header-anchor" href="#プランの追加" aria-label="Permalink to &quot;プランの追加&quot;">​</a></h3><ol><li>「プラン追加」ボタンをクリックします</li><li>モーダルが開きます</li><li>以下のフィールドに入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>プラン名</td><td>テキスト</td><td>✅</td><td>—</td><td>日本語名（例：「90分食べ放題」）</td></tr><tr><td>プラン名（英語）</td><td>テキスト</td><td>—</td><td>—</td><td>英語名（例：「90min All-You-Can-Eat」）</td></tr><tr><td>制限時間（分）</td><td>数値</td><td>✅</td><td>90</td><td>プランの時間制限（最小1分）</td></tr><tr><td>ラストオーダー（分前）</td><td>数値</td><td>—</td><td>15</td><td>終了の何分前にラストオーダーとするか</td></tr><tr><td>価格（円）</td><td>数値</td><td>—</td><td>0</td><td>プラン料金</td></tr><tr><td>並び順</td><td>数値</td><td>—</td><td>0</td><td>表示順（小さいほど上）</td></tr><tr><td>説明</td><td>テキストエリア（2行）</td><td>—</td><td>—</td><td>プランの説明文</td></tr></tbody></table><ol start="4"><li>「保存」ボタンをクリックします</li></ol><h3 id="プランの編集" tabindex="-1">プランの編集 <a class="header-anchor" href="#プランの編集" aria-label="Permalink to &quot;プランの編集&quot;">​</a></h3><p>既存プランの編集では、上記フィールドに加えて以下が変更可能です。</p><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>説明</th></tr></thead><tbody><tr><td>有効/無効</td><td>セレクト</td><td>無効にすると着席時のプラン選択に表示されなくなります</td></tr></tbody></table><h3 id="プラン専用メニュー" tabindex="-1">プラン専用メニュー <a class="header-anchor" href="#プラン専用メニュー" aria-label="Permalink to &quot;プラン専用メニュー&quot;">​</a></h3><p>食べ放題プランには専用のメニュー品目を登録できます。「メニュー管理」ボタンをクリックすると、プランに紐づく品目の一覧が展開されます。</p><p><strong>品目の追加：</strong></p><ol><li>「+ 品目追加」ボタンをクリックします</li><li>モーダルが開きます</li><li>以下のフィールドに入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>品名</td><td>テキスト</td><td>✅</td><td>品目の日本語名</td></tr><tr><td>品名（英語）</td><td>テキスト</td><td>—</td><td>品目の英語名</td></tr><tr><td>カテゴリ</td><td>セレクト</td><td>—</td><td>分類カテゴリ</td></tr><tr><td>説明</td><td>テキストエリア（2行）</td><td>—</td><td>品目の説明</td></tr><tr><td>並び順</td><td>数値</td><td>—</td><td>表示順</td></tr></tbody></table><ol start="4"><li>「保存」ボタンをクリックします</li></ol><p>各品目は編集・削除が可能です。無効にすることもできます。</p><hr><h2 id="_10-2-コース料理" tabindex="-1">10.2 コース料理 <a class="header-anchor" href="#_10-2-コース料理" aria-label="Permalink to &quot;10.2 コース料理&quot;">​</a></h2><h3 id="コース一覧" tabindex="-1">コース一覧 <a class="header-anchor" href="#コース一覧" aria-label="Permalink to &quot;コース一覧&quot;">​</a></h3><p>「プラン・コース」タブ → 「コース管理」サブタブを選択すると、登録済みコースの一覧が表示されます。</p><p>各コースには以下の情報が表示されます。</p><table tabindex="0"><thead><tr><th>表示要素</th><th>説明</th></tr></thead><tbody><tr><td>コース名</td><td>日本語名（英語名があればカッコ内に表示）</td></tr><tr><td>フェーズ数</td><td>「3フェーズ」形式</td></tr><tr><td>価格</td><td>「¥5,000」形式</td></tr><tr><td>ステータスバッジ</td><td>有効/無効</td></tr><tr><td>説明</td><td>コースの説明文</td></tr></tbody></table><h3 id="コースの追加" tabindex="-1">コースの追加 <a class="header-anchor" href="#コースの追加" aria-label="Permalink to &quot;コースの追加&quot;">​</a></h3><ol><li>「コース追加」ボタンをクリックします</li><li>以下のフィールドに入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>コース名</td><td>テキスト</td><td>✅</td><td>—</td><td>日本語名（例：「松コース」）</td></tr><tr><td>コース名（英語）</td><td>テキスト</td><td>—</td><td>—</td><td>英語名</td></tr><tr><td>価格（円）</td><td>数値</td><td>—</td><td>0</td><td>コース料金</td></tr><tr><td>並び順</td><td>数値</td><td>—</td><td>0</td><td>表示順</td></tr><tr><td>説明</td><td>テキストエリア（2行）</td><td>—</td><td>—</td><td>コースの説明文</td></tr></tbody></table><ol start="3"><li>「保存」ボタンをクリックします</li></ol><h3 id="フェーズの管理" tabindex="-1">フェーズの管理 <a class="header-anchor" href="#フェーズの管理" aria-label="Permalink to &quot;フェーズの管理&quot;">​</a></h3><p>コース料理はフェーズ（段階）で構成されます。各フェーズは順番に提供される料理のグループです。</p><p><strong>例：松コース（3フェーズ）</strong></p><ol><li>フェーズ1「前菜」：サラダ ×1、スープ ×1</li><li>フェーズ2「メイン」：刺身盛り合わせ ×1、天ぷら ×1</li><li>フェーズ3「デザート」：抹茶アイス ×1、コーヒー ×1</li></ol><h3 id="フェーズの追加" tabindex="-1">フェーズの追加 <a class="header-anchor" href="#フェーズの追加" aria-label="Permalink to &quot;フェーズの追加&quot;">​</a></h3><ol><li>コースの「+ フェーズ追加」ボタンをクリックします</li><li>以下のフィールドに入力します</li></ol><table tabindex="0"><thead><tr><th>フィールド</th><th>種類</th><th>必須</th><th>説明</th></tr></thead><tbody><tr><td>フェーズ名</td><td>テキスト</td><td>✅</td><td>フェーズの名前（例：「前菜」）。プレースホルダー：「例: 前菜」</td></tr><tr><td>フェーズ名（英語）</td><td>テキスト</td><td>—</td><td>英語名</td></tr><tr><td>自動発火（分後）</td><td>数値</td><td>—</td><td>前のフェーズからN分後に自動で次のフェーズを開始。空欄の場合は手動で進める</td></tr><tr><td>品目</td><td>テキストエリア（4行）</td><td>✅</td><td>1行に1品目。形式：「品名」または「品名 ×数量」</td></tr></tbody></table><p><strong>品目の入力形式：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>サラダ</span></span>
<span class="line"><span>スープ ×2</span></span>
<span class="line"><span>刺身盛り合わせ ×1</span></span></code></pre></div><ul><li>数量を省略した場合は1として扱われます</li><li><code>×</code>（全角）と<code>x</code>（半角）のどちらも使用できます</li></ul><ol start="3"><li>「保存」ボタンをクリックします</li><li>フェーズ番号は自動的に連番で付与されます</li></ol><h3 id="フェーズの発火方式" tabindex="-1">フェーズの発火方式 <a class="header-anchor" href="#フェーズの発火方式" aria-label="Permalink to &quot;フェーズの発火方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>表示</th><th>動作</th></tr></thead><tbody><tr><td>手動</td><td>「手動」</td><td>KDS画面の「次フェーズ」ボタンで進める</td></tr><tr><td>自動</td><td>「自動 N分後」</td><td>前のフェーズ開始からN分後に自動で次のフェーズの料理がKDSに表示される</td></tr></tbody></table><h3 id="コースの運用フロー" tabindex="-1">コースの運用フロー <a class="header-anchor" href="#コースの運用フロー" aria-label="Permalink to &quot;コースの運用フロー&quot;">​</a></h3><ol><li><strong>コースを作成し、フェーズと品目を登録する</strong>（事前準備）</li><li><strong>お客さんの着席時にコースを選択する</strong>（ハンディPOSのテーブル状況タブ → 着席モーダル）</li><li><strong>フェーズ1の料理が自動的にKDSに表示される</strong></li><li><strong>キッチンスタッフが調理・提供する</strong></li><li><strong>KDS画面の「次フェーズ」ボタンで次のフェーズに進める</strong>（手動の場合）</li><li><strong>全フェーズが完了するまで繰り返す</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">コース削除時の注意</p><p>コースを削除すると、そのコースに紐づく全てのフェーズも削除されます（カスケード削除）。</p></div>`,47)])])}const u=d(e,[["render",h]]);export{c as __pageData,u as default};
